def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        remainder = capacity - item
        base_priority = 0
        if remainder == 0:
            base_priority = 0
        elif remainder < item * 0.25:
            base_priority = (remainder / capacity) ** 3 + 0.2
        elif remainder < item * 0.5:
            base_priority = (0.5 - remainder / capacity) ** 2 + 0.3
        else:
            base_priority = np.log1p(remainder) / capacity
        penalty = 0
        for offset in range(1, 6):
            left = i - offset
            right = i + offset
            weight = 0.1 / offset
            if left >= 0:
                left_cap = bins[left]
                if left_cap > 0:
                    penalty += weight * abs(capacity - left_cap) / left_cap
                    if remainder < left_cap * 0.3:
                        penalty += 0.05 * offset
            if right < n:
                right_cap = bins[right]
                if right_cap > 0:
                    penalty += weight * abs(capacity - right_cap) / right_cap
                    if remainder < right_cap * 0.3:
                        penalty += 0.05 * (6 - offset)
        extra_factor = 1 + ((i * 7) % 5) * 0.07
        if capacity < item * 1.2:
            base_priority *= 2 - remainder / capacity
        if remainder > item * 2 and (i % 2 == 0):
            base_priority /= (1 + np.sqrt(remainder))
        priority = base_priority + penalty
        if priority < 0:
            priority = 0
        priorities[i] = priority * extra_factor
    min_val = np.min(priorities[np.isfinite(priorities)])
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_val * 20
    return priorities
